const {BigQuery} = require('@google-cloud/bigquery');
const {Storage} = require('@google-cloud/storage');

// Set up BigQuery and Storage clients
const bigquery = new BigQuery({
  projectId: 'your-project-id',
});

const storage = new Storage({
  projectId: 'your-project-id',
});

exports.processBigData = async (req, res) => {
  try {
    // Set maximum memory allocation to 8GB
    process.env.NODE_OPTIONS = '--max-old-space-size=8192';

    // Set timeout to 540 seconds
    const timeout = 540 * 1000;

    // Aggregate data from BigQuery
    const query = `SELECT * FROM your-table`;
    const options = {
      maxResults: 10000,
    };
    const [rows] = await bigquery.query(query, options);

    // Process the aggregated data
    const processedData = rows.map((row) => {
      return {
        id: row.id,
        name: row.name,
      };
    });

    // Save processed data to Cloud Storage
    const bucketName = 'your-bucket-name';
    const fileName = 'processed-data.json';
    const file = storage.bucket(bucketName).file(fileName);
    await file.save(processedData, {
      contentType: 'application/json',
    });

    res.status(200).send('Processing completed successfully');
  } catch (error) {
    console.error(error);
    res.status(500).send('Error processing big data');
  }
};